using Microsoft.ML.Data;

namespace TicketClassifier.Models;

/// <summary>Input schema matching the training CSV.</summary>
public class TicketData
{
    [LoadColumn(0)] public string Subject { get; set; } = "";
    [LoadColumn(1)] public string Description { get; set; } = "";
    [LoadColumn(2)] public float Priority { get; set; }
    [LoadColumn(3)] public string Category { get; set; } = "";
}

/// <summary>ML.NET prediction output.</summary>
public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = "";

    public float[] Score { get; set; } = [];
}

/// <summary>API request body.</summary>
public class TicketRequest
{
    public string Subject { get; set; } = "";
    public string Description { get; set; } = "";
    public int Priority { get; set; }
}

/// <summary>API response body.</summary>
public class TicketResponse
{
    public string PredictedCategory { get; set; } = "";
    public Dictionary<string, float> Probabilities { get; set; } = new();
}

/// <summary>Training evaluation metrics returned by the /metrics endpoint.</summary>
public class EvaluationMetrics
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly EvaluationMetrics _metrics;
    private readonly string[] _labels;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Build the training pipeline
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(dataView);

        // Evaluate against the training data (small dataset — no separate test split)
        var predictions = _model.Transform(dataView);
        var mlMetrics = _mlContext.MulticlassClassification.Evaluate(predictions, "Label");
        _metrics = new EvaluationMetrics
        {
            MacroAccuracy = mlMetrics.MacroAccuracy,
            MicroAccuracy = mlMetrics.MicroAccuracy,
            LogLoss = mlMetrics.LogLoss,
            LogLossReduction = mlMetrics.LogLossReduction
        };

        // Extract ordered label names so we can map Score[] → category
        var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
        _model.GetOutputSchema(dataView.Schema)["Score"]
              .GetSlotNames(ref labelBuffer);
        _labels = labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();

        _predictionEngine = _mlContext.Model
            .CreatePredictionEngine<TicketData, TicketPrediction>(_model);
    }

    public TicketResponse Predict(TicketRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(input);

        var probabilities = new Dictionary<string, float>();
        for (var i = 0; i < _labels.Length; i++)
            probabilities[_labels[i]] = prediction.Score[i];

        return new TicketResponse
        {
            PredictedCategory = prediction.Category,
            Probabilities = probabilities
        };
    }

    public EvaluationMetrics GetMetrics() => _metrics;
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    /// <summary>Predict the category for a support ticket.</summary>
    [HttpPost("classify")]
    public ActionResult<TicketResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) || string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject and Description are required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        return Ok(_classifier.Predict(request));
    }

    /// <summary>Return model evaluation metrics.</summary>
    [HttpGet("metrics")]
    public ActionResult<EvaluationMetrics> Metrics()
    {
        return Ok(_classifier.GetMetrics());
    }
}

